  ('P001', 'BR001', 'SUP001', 'CAT_DRIVERS', 'Apex Canyon Golf LaunchMax Carbon Driver', 'LaunchMax Carbon', 2025, 'Spring', 'Current', 'Core', 'mid-handicap golfers needing easier launch', '0-8', 'Adjustable driver built for ball speed, launch tuning, and stable misses.', 'Apex Canyon Golf LaunchMax Carbon Driver uses a lightweight crown, reinforced sole frame, and adjustable rear weighting to help golfers tune launch window and shot shape. The face is engineered for speed retention across common miss patterns, while the acoustics are damped for a solid, modern impact sound.', ARRAY<STRUCT<spec_name STRING, spec_value STRING>>[STRUCT('Head Volume' AS spec_name, '460 cc' AS spec_value), STRUCT('Loft Options' AS spec_name, '9, 10.5, and 12 degrees' AS spec_value), STRUCT('Face Material' AS spec_name, 'Variable-thickness titanium alloy' AS spec_value), STRUCT('Launch Profile' AS spec_name, 'Mid-high launch' AS spec_value), STRUCT('Spin Profile' AS spec_name, 'Mid spin' AS spec_value), STRUCT('Adjustability' AS spec_name, 'Eight-position hosel and rear weight track' AS spec_value)], ['driver', 'adjustable', 'forgiving', 'distance'], FALSE, TRUE, TRUE, TIMESTAMP '2026-07-07 00:00:00+00', TIMESTAMP '2026-07-07 00:00:00+00'),
