  ('P015', 'BR001', 'SUP001', 'CAT_HYBRIDS', 'Apex Canyon Golf RescueArc 3-Hybrid', 'RescueArc', 2026, 'Spring', 'Current', 'Core', 'golfers who want confidence from rough and fairway', '5-15', 'Confidence-building hybrid that replaces difficult long irons.', 'Apex Canyon Golf RescueArc 3-Hybrid is designed as a reliable bridge between fairway woods and irons. The head sits square, launches easily, and adds enough sole relief to work from uneven lies, making it a practical option for long approach shots and recovery play.', ARRAY<STRUCT<spec_name STRING, spec_value STRING>>[STRUCT('Loft Options' AS spec_name, '20, 23, and 26 degrees' AS spec_value), STRUCT('Head Shape' AS spec_name, 'Rounded confidence profile' AS spec_value), STRUCT('Launch Profile' AS spec_name, 'High launch' AS spec_value), STRUCT('Turf Interaction' AS spec_name, 'Railed sole with softened leading edge' AS spec_value), STRUCT('Stock Shaft' AS spec_name, 'Lightweight graphite' AS spec_value)], ['hybrid', 'long iron replacement', 'forgiving'], FALSE, TRUE, TRUE, TIMESTAMP '2026-07-07 00:00:00+00', TIMESTAMP '2026-07-07 00:00:00+00'),
