  ('RS001', 'P001', DATE '2026-06-30', 4.45, 190, 119, 48, 15, 5, 3, 'Ball speed stayed strong on slight toe strikes and the adjustable weight helped me reduce my fade.', 'The adjustability helps, but the headcover is tighter than it needs to be.', 'comfort', 0.93, 86.3, TIMESTAMP '2026-07-07 00:00:00+00'),
  ('RS002', 'P002', DATE '2026-06-30', 4.02, 485, 204, 155, 78, 29, 19, 'Easy to launch without feeling oversized, and the sound is solid rather than sharp.', 'Forgiveness is strong, but the impact sound is a little louder than I prefer.', 'feel', 0.82, 78.5, TIMESTAMP '2026-07-07 00:00:00+00'),
  ('RS003', 'P003', DATE '2026-06-30', 4.01, 193, 80, 62, 31, 12, 8, 'Easy to launch without feeling oversized, and the sound is solid rather than sharp.', 'Great distance, although the stock grip felt slick after a few humid holes.', 'durability', 0.88, 80, TIMESTAMP '2026-07-07 00:00:00+00'),
  ('RS004', 'P004', DATE '2026-06-30', 4.46, 725, 457, 181, 58, 18, 11, 'Easy to launch without feeling oversized, and the sound is solid rather than sharp.', 'The adjustability helps, but the headcover is tighter than it needs to be.', 'alignment', 0.93, 79.7, TIMESTAMP '2026-07-07 00:00:00+00'),
  ('RS005', 'P005', DATE '2026-06-30', 4.21, 105, 53, 32, 12, 5, 3, 'Easy to launch without feeling oversized, and the sound is solid rather than sharp.', 'Forgiveness is strong, but the impact sound is a little louder than I prefer.', 'value', 0.82, 76.7, TIMESTAMP '2026-07-07 00:00:00+00'),
  ('RS006', 'P006', DATE '2026-06-30', 4.02, 683, 287, 219, 109, 41, 27, 'The head feels stable at impact and the stock shaft did not feel loose during full swings.', 'Great distance, although the stock grip felt slick after a few humid holes.', 'forgiveness', 0.73, 79.6, TIMESTAMP '2026-07-07 00:00:00+00'),
  ('RS007', 'P007', DATE '2026-06-30', 4.19, 26, 13, 8, 3, 1, 1, 'Ball speed stayed strong on slight toe strikes and the adjustable weight helped me reduce my fade.', 'Forgiveness is strong, but the impact sound is a little louder than I prefer.', 'weather performance', 0.82, 81.1, TIMESTAMP '2026-07-07 00:00:00+00'),
  ('RS008', 'P008', DATE '2026-06-30', 4.25, 219, 114, 66, 24, 10, 5, 'The head feels stable at impact and the stock shaft did not feel loose during full swings.', 'Great distance, although the stock grip felt slick after a few humid holes.', 'fit', 0.84, 81.2, TIMESTAMP '2026-07-07 00:00:00+00'),
  ('RS009', 'P009', DATE '2026-06-30', 4.45, 272, 171, 68, 22, 7, 4, 'Strong carry distance with enough height to hold a green on long approaches.', 'Solid club, though the shallow face took a range session to get used to.', 'alignment', 0.78, 79.4, TIMESTAMP '2026-07-07 00:00:00+00'),
  ('RS010', 'P010', DATE '2026-06-30', 4.46, 858, 541, 214, 69, 21, 13, 'The sole glides through tight lies better than my old fairway wood.', 'Good from turf, but the finish showed a small sole mark quickly.', 'weather performance', 0.76, 83, TIMESTAMP '2026-07-07 00:00:00+00'),
  ('RS011', 'P011', DATE '2026-06-30', 4.66, 388, 294, 70, 16, 4, 4, 'The sole glides through tight lies better than my old fairway wood.', 'Good from turf, but the finish showed a small sole mark quickly.', 'durability', 0.89, 85.9, TIMESTAMP '2026-07-07 00:00:00+00'),
