INSERT INTO `affable-seat-501018-q0.golf_products.dim_card_offers` (card_offer_id, payment_method_id, offer_name, issuer_name, card_network, card_type, promotional_apr_percent, promotional_period_months, purchase_apr_min_percent, purchase_apr_max_percent, annual_fee, late_fee_up_to, returned_payment_fee_up_to, rewards_rate_description, signup_bonus_description, eligibility_summary, application_disclosure, responsible_use_note, terms_url, effective_start_date, effective_end_date, is_active) VALUES
  ('CARD_STORE_12MO_500', 'PM_GOLF_STORE_CARD', '0% APR for 12 Months on $500+', 'Example Bank N.A.', 'Private Label', 'Store Credit Card', NUMERIC '0.00', 12, NUMERIC '19.99', NUMERIC '31.99', NUMERIC '0.00', NUMERIC '40.00', NUMERIC '30.00', 'Earn 2 points per $1 on eligible store purchases.', 'New cardmembers may receive 5,000 bonus points after first eligible purchase.', 'Subject to credit approval. Promotional terms require a qualifying purchase of $500 or more.', 'Application may affect credit score. Full terms are provided before submission.', 'Pay the promotional balance in full before the period ends to avoid deferred or accrued interest where applicable.', 'https://example.invalid/terms/store-card-12mo', DATE '2026-07-01', DATE '2026-12-31', TRUE),
  ('CARD_STORE_18MO_1500', 'PM_GOLF_STORE_CARD', 'Reduced APR for 18 Months on $1,500+', 'Example Bank N.A.', 'Private Label', 'Store Credit Card', NUMERIC '9.99', 18, NUMERIC '19.99', NUMERIC '31.99', NUMERIC '0.00', NUMERIC '40.00', NUMERIC '30.00', 'Earn 2 points per $1 on eligible store purchases.', 'No signup bonus on reduced APR plan.', 'Subject to credit approval. Available for qualifying larger purchases such as full club sets or launch monitors.', 'Application may affect credit score. Full terms are provided before submission.', 'Compare total interest against paying in full or choosing a lower-cost product.', 'https://example.invalid/terms/store-card-18mo', DATE '2026-07-01', DATE '2026-12-31', TRUE),
  ('CARD_REWARDS_VISA_EVERYDAY', 'PM_GOLF_REWARDS_VISA', 'Golf Rewards Visa Everyday Points', 'Example Bank N.A.', 'Visa', 'Co-Branded Credit Card', NULL, NULL, NUMERIC '18.99', NUMERIC '29.99', NUMERIC '0.00', NUMERIC '40.00', NUMERIC '30.00', 'Earn 3 points per $1 at the golf store, 2 points per $1 on gas and dining, and 1 point per $1 elsewhere.', '10,000 bonus points after $750 in purchases within 90 days, subject to terms.', 'Subject to credit approval and account terms.', 'Application may affect credit score. Rewards values and redemption rules may change.', 'Rewards can be useful if paid in full; carrying a balance may cost more than rewards are worth.', 'https://example.invalid/terms/rewards-visa', DATE '2026-07-01', NULL, TRUE);
INSERT INTO `affable-seat-501018-q0.golf_products.dim_installment_plan_offers` (installment_offer_id, payment_method_id, provider_name, plan_name, min_purchase_amount, max_purchase_amount, term_months, apr_min_percent, apr_max_percent, fees_summary, eligibility_summary, repayment_summary, disclosure, responsible_use_note, effective_start_date, effective_end_date, is_active) VALUES
  ('INST_FAIRWAYPAY_STANDARD', 'PM_INSTALLMENTS', 'FairwayPay', 'Fixed Monthly Installments', NUMERIC '150.00', NUMERIC '5000.00', [3, 6, 12], NUMERIC '0.00', NUMERIC '29.99', 'No late fees from the store; provider terms may include interest depending on eligibility.', 'Subject to eligibility check by FairwayPay. Not all customers or purchases qualify.', 'Equal monthly payments over the selected term. First payment may be due at checkout.', 'APR and payment schedule are shown before the customer accepts the plan.', 'Choose a term only if the monthly payment fits the customer budget after regular expenses.', DATE '2026-07-01', NULL, TRUE),
  ('INST_LAUNCHMONITOR_24', 'PM_INSTALLMENTS', 'FairwayPay', 'Launch Monitor Extended Plan', NUMERIC '1000.00', NUMERIC '10000.00', [12, 18, 24], NUMERIC '7.99', NUMERIC '24.99', 'Interest-bearing plan for higher-ticket technology purchases.', 'Subject to eligibility check and purchase amount. May not combine with all promotions.', 'Fixed monthly payments over 12, 18, or 24 months.', 'Total cost may exceed cash price when APR is above 0%.', 'Review total repayment cost before choosing this option.', DATE '2026-07-01', DATE '2026-12-31', TRUE);
