INSERT INTO `affable-seat-501018-q0.golf_products.dim_return_policies` (return_policy_id, category_id, policy_name, return_window_days, condition_requirements, restocking_fee_percent, return_shipping_responsibility, refund_method, exclusions, policy_notes) VALUES
  ('RET_STANDARD', NULL, 'Standard Unused Item Return', 30, 'Item must be unused, in original packaging, with tags, manuals, and accessories.', NUMERIC '0.00', 'Customer pays return shipping unless the item arrived damaged or incorrect.', 'Original payment method after inspection.', 'Gift cards, final-sale items, and personalized products are excluded.', 'Most unused products follow this policy unless a category-specific policy applies.'),
  ('RET_CLUBS_STANDARD', 'CAT_DRIVERS', 'Golf Club Return', 30, 'Clubs must be unused or hit only in an approved indoor trial condition with no visible wear.', NUMERIC '0.00', 'Customer pays return shipping unless damaged or incorrect.', 'Original payment method after inspection.', 'Custom-fit, altered, or personalized clubs may be non-returnable.', 'Drivers and woods should be returned with headcover, wrench, and original packaging when included.'),
  ('RET_CUSTOM_CLUBS', 'CAT_IRONS', 'Custom-Fit Club Return Restriction', 14, 'Custom-fit clubs are reviewed case by case and must be in like-new condition.', NUMERIC '15.00', 'Customer pays return shipping.', 'Store credit or original payment method depending on build status.', 'Personalized stamping, non-standard shafts, and special orders may be final sale.', 'Encourage customers to verify specs before checkout.'),
  ('RET_APPAREL_SHOES', 'CAT_APPAREL', 'Apparel Return', 30, 'Items must be unworn, unwashed, and have original tags attached.', NUMERIC '0.00', 'Customer pays return shipping unless damaged or incorrect.', 'Original payment method after inspection.', 'Final-sale clearance apparel is excluded.', 'Sizing exchanges are supported when inventory is available.'),
  ('RET_SHOES', 'CAT_SHOES', 'Golf Shoe Return', 30, 'Shoes must be unworn outdoors and returned with original box.', NUMERIC '0.00', 'Customer pays return shipping unless damaged or incorrect.', 'Original payment method after inspection.', 'Shoes with course wear, grass stains, or removed tags may be declined.', 'Try shoes indoors before wearing them on course.');
INSERT INTO `affable-seat-501018-q0.golf_products.dim_warranty_policies` (warranty_policy_id, category_id, policy_name, coverage_months, coverage_provider, covered_issues, excluded_issues, claim_requirements, support_contact, policy_notes) VALUES
  ('WAR_STANDARD', NULL, 'General Manufacturer Warranty', 12, 'Manufacturer', 'Manufacturing defects in materials or workmanship under normal use.', 'Normal wear, misuse, accidental damage, cosmetic wear, and unauthorized repairs.', 'Order number, product photos, description of issue, and proof of purchase.', 'support@example.invalid', 'Coverage varies by brand and product type.'),
  ('WAR_CLUBS', 'CAT_DRIVERS', 'Club Head and Shaft Warranty', 24, 'Manufacturer', 'Club head structural defects, shaft defects, and adapter failures under normal use.', 'Sky marks, dents from misuse, broken shafts from abuse, and custom alterations.', 'Order number, serial number if present, photos of club head/shaft, and usage description.', 'clubs-warranty@example.invalid', 'Warranty replacement specs may vary based on available inventory.'),
  ('WAR_BAGS', 'CAT_BAGS', 'Golf Bag Hardware Warranty', 12, 'Store and manufacturer', 'Stand mechanism, strap, zipper, and seam failures under normal carrying use.', 'Airline damage, overloaded pockets, stains, and normal abrasion.', 'Order number, photos of failed component, and bag SKU.', 'bags-warranty@example.invalid', 'Travel damage should be filed with the carrier first.'),
  ('WAR_SHOES', 'CAT_SHOES', 'Waterproof Shoe Warranty', 12, 'Manufacturer', 'Waterproof membrane failure under normal golf use on eligible models.', 'Wear-through, improper care, cuts, sole wear, and non-waterproof models.', 'Order number, photos, model name, and explanation of water intrusion.', 'shoes-warranty@example.invalid', 'Waterproof coverage applies only to models sold as waterproof.'),
  ('WAR_TECH', 'CAT_TRAINING_AIDS', 'Electronics and Training Aid Warranty', 12, 'Manufacturer', 'Electronic component defects, sensor failure, and display failure under normal use.', 'Battery wear, cracked screens, water damage, and unauthorized software modifications.', 'Order number, serial number, diagnostic screenshots, and photos.', 'tech-warranty@example.invalid', 'Some electronics require manufacturer registration for full warranty support.');
INSERT INTO `affable-seat-501018-q0.golf_products.dim_checkout_guidance` (checkout_step_id, step_order, step_name, description, data_required, applies_to, risk_note, created_at) VALUES
  ('CHK_REVIEW_CART', 1, 'Review cart and fit details', 'Confirm product, variant, dexterity, shaft flex, loft, size, color, quantity, and custom-fit selections before payment.', ['product_id', 'variant_id', 'quantity', 'fit_specs'], 'All orders', 'Custom-fit or personalized selections may restrict returns.', TIMESTAMP '2026-07-07 00:00:00+00'),
  ('CHK_APPLY_DISCOUNTS', 2, 'Apply discounts and loyalty rewards', 'Apply coupon codes, member discounts, loyalty points, gift cards, and eligible promotions before choosing payment.', ['coupon_code', 'loyalty_member_id', 'points_to_redeem'], 'Orders with promotions or loyalty redemption', 'Some offers do not stack with financing or other promotions.', TIMESTAMP '2026-07-07 00:00:00+00'),
  ('CHK_SHIPPING', 3, 'Choose shipping', 'Select shipping speed, confirm address, review oversize fees, and note custom-fit build time when applicable.', ['shipping_address', 'shipping_service_id'], 'Physical goods', 'Estimated delivery can change for custom-fit builds, preorder items, or remote ZIP codes.', TIMESTAMP '2026-07-07 00:00:00+00'),
  ('CHK_PAYMENT', 4, 'Choose payment or financing', 'Select pay-in-full, store card, co-branded card, or installment option and review APR, fees, payment schedule, and eligibility requirements.', ['payment_method_id', 'billing_address'], 'All paid orders', 'Do not assume approval or choose financing unless the total repayment fits the customer budget.', TIMESTAMP '2026-07-07 00:00:00+00'),
  ('CHK_CONFIRM', 5, 'Confirm order', 'Review merchandise subtotal, discounts, estimated taxes, shipping, financing disclosures, total cost, and return/warranty links before placing the order.', ['order_total', 'tax_estimate', 'terms_acceptance'], 'All orders', 'The customer should save confirmation details for support, returns, and warranty claims.', TIMESTAMP '2026-07-07 00:00:00+00');
