-- BigQuery Standard SQL
-- Synthetic golf retail star schema / mini data warehouse.
-- Replace `affable-seat-501018-q0` with your actual Google Cloud project ID before running.
--
-- Product and brand names are fictional and anonymized.
-- They are not affiliated with, endorsed by, or copied from any real golf brand.
-- The data intentionally includes realistic quirks: missing UPCs, low stock, backorders,
-- clearance items, discontinued products, preorder products, uneven review counts,
-- returns, discounts, and category-specific variants.

CREATE SCHEMA IF NOT EXISTS `affable-seat-501018-q0.golf_products`
OPTIONS(
  location = 'US',
  description = 'Synthetic golf retail dataset with products, variants, inventory, reviews, pricing, sales, and performance metrics.'
);

