CREATE OR REPLACE VIEW `affable-seat-501018-q0.golf_products.vw_product_catalog_current` AS
WITH latest_inventory AS (
  SELECT * EXCEPT(row_num)
  FROM (
    SELECT
      i.*,
      ROW_NUMBER() OVER (PARTITION BY variant_id ORDER BY snapshot_date DESC) AS row_num
    FROM `affable-seat-501018-q0.golf_products.fact_inventory_snapshots` AS i
  )
  WHERE row_num = 1
),
current_prices AS (
  SELECT *
  FROM `affable-seat-501018-q0.golf_products.fact_price_history`
  WHERE effective_end_date IS NULL
)
SELECT
  p.product_id,
  v.variant_id,
  v.sku,
  v.upc,
  p.product_name,
  b.brand_name,
  c.category_name,
  c.parent_category,
  p.model_year,
  p.release_season,
  p.product_status,
  p.lifecycle_stage,
  p.target_player_profile,
  p.handicap_range,
  v.gender,
  v.handedness,
  v.color,
  v.size,
  v.loft,
  v.bounce,
  v.grind,
  v.shaft_flex,
  v.shaft_material,
  v.ball_color,
  v.pack_size,
  v.shoe_size,
  v.shoe_width,
  v.apparel_fit,
  cp.msrp,
  cp.sale_price AS current_sale_price,
  v.cost,
  ROUND(SAFE_DIVIDE(CAST(cp.sale_price - v.cost AS FLOAT64), CAST(cp.sale_price AS FLOAT64)) * 100, 2) AS margin_percent,
  li.snapshot_date AS inventory_snapshot_date,
  li.warehouse_location,
  li.stock_quantity,
  li.reserved_quantity,
  li.reorder_level,
  li.inventory_status,
  r.average_rating,
  r.review_count,
  r.sample_positive_review,
  r.sample_negative_review,
  p.short_description,
  p.long_description,
  CASE p.category_id
    WHEN 'CAT_DRIVERS' THEN 'https://upload.wikimedia.org/wikipedia/commons/f/f4/Golf_drivers_old_and_new.jpg'
    WHEN 'CAT_FAIRWAY' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/03/Golf_clubs.jpg'
    WHEN 'CAT_HYBRIDS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/0d/Golf_club%2C_Ping_G10_24%C2%BA_hybrid.jpg'
    WHEN 'CAT_IRONS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/03/Golf_clubs.jpg'
    WHEN 'CAT_WEDGES' THEN 'https://upload.wikimedia.org/wikipedia/commons/3/34/Metal_clubs.jpg'
    WHEN 'CAT_PUTTERS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/0e/Putter_with_insert.jpg'
    WHEN 'CAT_BALLS' THEN 'https://upload.wikimedia.org/wikipedia/commons/e/e6/Golfball.jpg'
    WHEN 'CAT_GLOVES' THEN 'https://upload.wikimedia.org/wikipedia/commons/4/41/Golf_glove.jpg'
    WHEN 'CAT_BAGS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/00/Golf_bag_near_green.jpg'
    WHEN 'CAT_POLOS' THEN 'https://upload.wikimedia.org/wikipedia/commons/d/de/Paula_Creamer_IMG_0686_%286376796787%29.jpg'
    WHEN 'CAT_OUTERWEAR' THEN 'https://upload.wikimedia.org/wikipedia/commons/d/de/Paula_Creamer_IMG_0686_%286376796787%29.jpg'
    WHEN 'CAT_PANTS' THEN 'https://upload.wikimedia.org/wikipedia/commons/d/de/Paula_Creamer_IMG_0686_%286376796787%29.jpg'
    WHEN 'CAT_SHOES' THEN 'https://upload.wikimedia.org/wikipedia/commons/5/59/Golf_gear.jpg'
    WHEN 'CAT_RANGEFINDERS' THEN 'https://upload.wikimedia.org/wikipedia/commons/3/3b/Golfers_on_green.jpg'
    WHEN 'CAT_TRAINING' THEN 'https://upload.wikimedia.org/wikipedia/commons/6/6e/Golfer_swing.jpg'
    WHEN 'CAT_ACCESSORIES' THEN 'https://upload.wikimedia.org/wikipedia/commons/5/59/Golf_gear.jpg'
  END AS image_url,
  CASE p.category_id
    WHEN 'CAT_DRIVERS' THEN 'Real golf driver heads photographed close up.'
    WHEN 'CAT_FAIRWAY' THEN 'Real golf clubs in a bag on a golf course.'
    WHEN 'CAT_HYBRIDS' THEN 'Real hybrid golf club head on turf.'
    WHEN 'CAT_IRONS' THEN 'Real golf irons in a bag on a golf course.'
    WHEN 'CAT_WEDGES' THEN 'Real metal golf wedges photographed close up.'
    WHEN 'CAT_PUTTERS' THEN 'Real golf putter head photographed close up.'
    WHEN 'CAT_BALLS' THEN 'Real white golf ball beside a cup on a putting green.'
    WHEN 'CAT_GLOVES' THEN 'Real white golf glove on grass.'
    WHEN 'CAT_BAGS' THEN 'Real golf bag resting near a green.'
    WHEN 'CAT_POLOS' THEN 'Golfer wearing a pink golf polo on the course.'
    WHEN 'CAT_OUTERWEAR' THEN 'Golfer wearing golf apparel on the course.'
    WHEN 'CAT_PANTS' THEN 'Golfer wearing golf pants and shorts on the course.'
    WHEN 'CAT_SHOES' THEN 'Real golf shoes packed with golf bags.'
    WHEN 'CAT_RANGEFINDERS' THEN 'Golfers and equipment on a putting green.'
    WHEN 'CAT_TRAINING' THEN 'Golfer swinging on a tee box during practice.'
    WHEN 'CAT_ACCESSORIES' THEN 'Real golf gear including shoes and bags.'
  END AS image_alt,
  [
    CASE p.category_id
      WHEN 'CAT_DRIVERS' THEN 'https://upload.wikimedia.org/wikipedia/commons/f/f4/Golf_drivers_old_and_new.jpg'
      WHEN 'CAT_FAIRWAY' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/03/Golf_clubs.jpg'
      WHEN 'CAT_HYBRIDS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/0d/Golf_club%2C_Ping_G10_24%C2%BA_hybrid.jpg'
      WHEN 'CAT_IRONS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/03/Golf_clubs.jpg'
      WHEN 'CAT_WEDGES' THEN 'https://upload.wikimedia.org/wikipedia/commons/3/34/Metal_clubs.jpg'
      WHEN 'CAT_PUTTERS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/0e/Putter_with_insert.jpg'
      WHEN 'CAT_BALLS' THEN 'https://upload.wikimedia.org/wikipedia/commons/e/e6/Golfball.jpg'
      WHEN 'CAT_GLOVES' THEN 'https://upload.wikimedia.org/wikipedia/commons/4/41/Golf_glove.jpg'
      WHEN 'CAT_BAGS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/00/Golf_bag_near_green.jpg'
      WHEN 'CAT_POLOS' THEN 'https://upload.wikimedia.org/wikipedia/commons/d/de/Paula_Creamer_IMG_0686_%286376796787%29.jpg'
      WHEN 'CAT_OUTERWEAR' THEN 'https://upload.wikimedia.org/wikipedia/commons/d/de/Paula_Creamer_IMG_0686_%286376796787%29.jpg'
      WHEN 'CAT_PANTS' THEN 'https://upload.wikimedia.org/wikipedia/commons/d/de/Paula_Creamer_IMG_0686_%286376796787%29.jpg'
      WHEN 'CAT_SHOES' THEN 'https://upload.wikimedia.org/wikipedia/commons/5/59/Golf_gear.jpg'
      WHEN 'CAT_RANGEFINDERS' THEN 'https://upload.wikimedia.org/wikipedia/commons/3/3b/Golfers_on_green.jpg'
      WHEN 'CAT_TRAINING' THEN 'https://upload.wikimedia.org/wikipedia/commons/6/6e/Golfer_swing.jpg'
      WHEN 'CAT_ACCESSORIES' THEN 'https://upload.wikimedia.org/wikipedia/commons/5/59/Golf_gear.jpg'
    END
  ] AS image_uris,
  p.specs,
  p.tags
FROM `affable-seat-501018-q0.golf_products.dim_products` AS p
JOIN `affable-seat-501018-q0.golf_products.dim_brands` AS b
  ON p.brand_id = b.brand_id
JOIN `affable-seat-501018-q0.golf_products.dim_categories` AS c
  ON p.category_id = c.category_id
JOIN `affable-seat-501018-q0.golf_products.dim_product_variants` AS v
  ON p.product_id = v.product_id
LEFT JOIN current_prices AS cp
  ON v.variant_id = cp.variant_id
LEFT JOIN latest_inventory AS li
  ON v.variant_id = li.variant_id
LEFT JOIN `affable-seat-501018-q0.golf_products.fact_product_reviews` AS r
  ON p.product_id = r.product_id;

CREATE OR REPLACE VIEW `affable-seat-501018-q0.golf_products.vw_low_stock_best_sellers` AS
WITH latest_inventory AS (
  SELECT * EXCEPT(row_num)
  FROM (
    SELECT
      i.*,
      ROW_NUMBER() OVER (PARTITION BY variant_id ORDER BY snapshot_date DESC) AS row_num
    FROM `affable-seat-501018-q0.golf_products.fact_inventory_snapshots` AS i
  )
  WHERE row_num = 1
)
SELECT
  p.product_id,
  p.product_name,
  c.category_name,
  SUM(li.stock_quantity) AS total_stock_quantity,
  SUM(li.reserved_quantity) AS total_reserved_quantity,
  SUM(li.reorder_level) AS total_reorder_level,
  STRING_AGG(DISTINCT li.inventory_status, ', ' ORDER BY li.inventory_status) AS inventory_statuses,
  perf.units_sold_30d,
  perf.units_sold_90d,
  perf.net_revenue_90d,
  r.average_rating,
  r.review_count,
  ANY_VALUE(
    CASE p.category_id
      WHEN 'CAT_DRIVERS' THEN 'https://upload.wikimedia.org/wikipedia/commons/f/f4/Golf_drivers_old_and_new.jpg'
      WHEN 'CAT_FAIRWAY' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/03/Golf_clubs.jpg'
      WHEN 'CAT_HYBRIDS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/0d/Golf_club%2C_Ping_G10_24%C2%BA_hybrid.jpg'
      WHEN 'CAT_IRONS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/03/Golf_clubs.jpg'
      WHEN 'CAT_WEDGES' THEN 'https://upload.wikimedia.org/wikipedia/commons/3/34/Metal_clubs.jpg'
      WHEN 'CAT_PUTTERS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/0e/Putter_with_insert.jpg'
      WHEN 'CAT_BALLS' THEN 'https://upload.wikimedia.org/wikipedia/commons/e/e6/Golfball.jpg'
      WHEN 'CAT_GLOVES' THEN 'https://upload.wikimedia.org/wikipedia/commons/4/41/Golf_glove.jpg'
      WHEN 'CAT_BAGS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/00/Golf_bag_near_green.jpg'
      WHEN 'CAT_POLOS' THEN 'https://upload.wikimedia.org/wikipedia/commons/d/de/Paula_Creamer_IMG_0686_%286376796787%29.jpg'
      WHEN 'CAT_OUTERWEAR' THEN 'https://upload.wikimedia.org/wikipedia/commons/d/de/Paula_Creamer_IMG_0686_%286376796787%29.jpg'
      WHEN 'CAT_PANTS' THEN 'https://upload.wikimedia.org/wikipedia/commons/d/de/Paula_Creamer_IMG_0686_%286376796787%29.jpg'
      WHEN 'CAT_SHOES' THEN 'https://upload.wikimedia.org/wikipedia/commons/5/59/Golf_gear.jpg'
      WHEN 'CAT_RANGEFINDERS' THEN 'https://upload.wikimedia.org/wikipedia/commons/3/3b/Golfers_on_green.jpg'
      WHEN 'CAT_TRAINING' THEN 'https://upload.wikimedia.org/wikipedia/commons/6/6e/Golfer_swing.jpg'
      WHEN 'CAT_ACCESSORIES' THEN 'https://upload.wikimedia.org/wikipedia/commons/5/59/Golf_gear.jpg'
    END
  ) AS image_url,
  ANY_VALUE(
    CASE p.category_id
      WHEN 'CAT_DRIVERS' THEN 'Real golf driver heads photographed close up.'
      WHEN 'CAT_FAIRWAY' THEN 'Real golf clubs in a bag on a golf course.'
      WHEN 'CAT_HYBRIDS' THEN 'Real hybrid golf club head on turf.'
      WHEN 'CAT_IRONS' THEN 'Real golf irons in a bag on a golf course.'
      WHEN 'CAT_WEDGES' THEN 'Real metal golf wedges photographed close up.'
      WHEN 'CAT_PUTTERS' THEN 'Real golf putter head photographed close up.'
      WHEN 'CAT_BALLS' THEN 'Real white golf ball beside a cup on a putting green.'
      WHEN 'CAT_GLOVES' THEN 'Real white golf glove on grass.'
      WHEN 'CAT_BAGS' THEN 'Real golf bag resting near a green.'
      WHEN 'CAT_POLOS' THEN 'Golfer wearing a pink golf polo on the course.'
      WHEN 'CAT_OUTERWEAR' THEN 'Golfer wearing golf apparel on the course.'
      WHEN 'CAT_PANTS' THEN 'Golfer wearing golf pants and shorts on the course.'
      WHEN 'CAT_SHOES' THEN 'Real golf shoes packed with golf bags.'
      WHEN 'CAT_RANGEFINDERS' THEN 'Golfers and equipment on a putting green.'
      WHEN 'CAT_TRAINING' THEN 'Golfer swinging on a tee box during practice.'
      WHEN 'CAT_ACCESSORIES' THEN 'Real golf gear including shoes and bags.'
    END
  ) AS image_alt,
  ARRAY_AGG(
    DISTINCT CASE p.category_id
      WHEN 'CAT_DRIVERS' THEN 'https://upload.wikimedia.org/wikipedia/commons/f/f4/Golf_drivers_old_and_new.jpg'
      WHEN 'CAT_FAIRWAY' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/03/Golf_clubs.jpg'
      WHEN 'CAT_HYBRIDS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/0d/Golf_club%2C_Ping_G10_24%C2%BA_hybrid.jpg'
      WHEN 'CAT_IRONS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/03/Golf_clubs.jpg'
      WHEN 'CAT_WEDGES' THEN 'https://upload.wikimedia.org/wikipedia/commons/3/34/Metal_clubs.jpg'
      WHEN 'CAT_PUTTERS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/0e/Putter_with_insert.jpg'
      WHEN 'CAT_BALLS' THEN 'https://upload.wikimedia.org/wikipedia/commons/e/e6/Golfball.jpg'
      WHEN 'CAT_GLOVES' THEN 'https://upload.wikimedia.org/wikipedia/commons/4/41/Golf_glove.jpg'
      WHEN 'CAT_BAGS' THEN 'https://upload.wikimedia.org/wikipedia/commons/0/00/Golf_bag_near_green.jpg'
      WHEN 'CAT_POLOS' THEN 'https://upload.wikimedia.org/wikipedia/commons/d/de/Paula_Creamer_IMG_0686_%286376796787%29.jpg'
      WHEN 'CAT_OUTERWEAR' THEN 'https://upload.wikimedia.org/wikipedia/commons/d/de/Paula_Creamer_IMG_0686_%286376796787%29.jpg'
      WHEN 'CAT_PANTS' THEN 'https://upload.wikimedia.org/wikipedia/commons/d/de/Paula_Creamer_IMG_0686_%286376796787%29.jpg'
      WHEN 'CAT_SHOES' THEN 'https://upload.wikimedia.org/wikipedia/commons/5/59/Golf_gear.jpg'
      WHEN 'CAT_RANGEFINDERS' THEN 'https://upload.wikimedia.org/wikipedia/commons/3/3b/Golfers_on_green.jpg'
      WHEN 'CAT_TRAINING' THEN 'https://upload.wikimedia.org/wikipedia/commons/6/6e/Golfer_swing.jpg'
      WHEN 'CAT_ACCESSORIES' THEN 'https://upload.wikimedia.org/wikipedia/commons/5/59/Golf_gear.jpg'
    END IGNORE NULLS LIMIT 3
  ) AS image_uris
FROM `affable-seat-501018-q0.golf_products.dim_products` AS p
JOIN `affable-seat-501018-q0.golf_products.dim_categories` AS c
  ON p.category_id = c.category_id
JOIN `affable-seat-501018-q0.golf_products.dim_product_variants` AS v
  ON p.product_id = v.product_id
JOIN latest_inventory AS li
  ON v.variant_id = li.variant_id
LEFT JOIN `affable-seat-501018-q0.golf_products.fact_product_performance_90d` AS perf
  ON p.product_id = perf.product_id
LEFT JOIN `affable-seat-501018-q0.golf_products.fact_product_reviews` AS r
  ON p.product_id = r.product_id
GROUP BY
  p.product_id,
  p.product_name,
  c.category_name,
  perf.units_sold_30d,
  perf.units_sold_90d,
  perf.net_revenue_90d,
  r.average_rating,
  r.review_count
HAVING SUM(li.stock_quantity) <= SUM(li.reorder_level)
   AND (perf.units_sold_30d >= 2 OR perf.units_sold_90d >= 8);

CREATE OR REPLACE VIEW `affable-seat-501018-q0.golf_products.vw_category_margin_summary` AS
WITH current_prices AS (
  SELECT *
  FROM `affable-seat-501018-q0.golf_products.fact_price_history`
  WHERE effective_end_date IS NULL
),
variant_prices AS (
  SELECT
    p.category_id,
    COUNT(DISTINCT p.product_id) AS product_count,
    COUNT(DISTINCT v.variant_id) AS variant_count,
    ROUND(AVG(CAST(cp.sale_price AS FLOAT64)), 2) AS avg_current_sale_price,
    ROUND(AVG(SAFE_DIVIDE(CAST(cp.sale_price - v.cost AS FLOAT64), CAST(cp.sale_price AS FLOAT64))) * 100, 2) AS avg_margin_percent
  FROM `affable-seat-501018-q0.golf_products.dim_products` AS p
  JOIN `affable-seat-501018-q0.golf_products.dim_product_variants` AS v
    ON p.product_id = v.product_id
  LEFT JOIN current_prices AS cp
    ON v.variant_id = cp.variant_id
  GROUP BY p.category_id
),
product_metrics AS (
  SELECT
    p.category_id,
    SUM(perf.units_sold_30d) AS units_sold_30d,
    SUM(perf.units_sold_90d) AS units_sold_90d,
    SUM(perf.net_revenue_90d) AS net_revenue_90d,
    ROUND(AVG(perf.return_rate), 4) AS avg_return_rate,
    ROUND(AVG(r.average_rating), 2) AS avg_rating
  FROM `affable-seat-501018-q0.golf_products.dim_products` AS p
  LEFT JOIN `affable-seat-501018-q0.golf_products.fact_product_performance_90d` AS perf
    ON p.product_id = perf.product_id
  LEFT JOIN `affable-seat-501018-q0.golf_products.fact_product_reviews` AS r
    ON p.product_id = r.product_id
  GROUP BY p.category_id
)
SELECT
  c.category_id,
  c.category_name,
  c.parent_category,
  vp.product_count,
  vp.variant_count,
  vp.avg_current_sale_price,
  vp.avg_margin_percent,
  pm.units_sold_30d,
  pm.units_sold_90d,
  pm.net_revenue_90d,
  pm.avg_return_rate,
  pm.avg_rating
FROM `affable-seat-501018-q0.golf_products.dim_categories` AS c
LEFT JOIN variant_prices AS vp
  ON c.category_id = vp.category_id
LEFT JOIN product_metrics AS pm
  ON c.category_id = pm.category_id;

CREATE OR REPLACE VIEW `affable-seat-501018-q0.golf_products.vw_active_financing_options` AS
SELECT
  'CARD' AS option_type,
  co.card_offer_id AS option_id,
  pm.payment_method_id,
  pm.method_name,
  co.offer_name,
  co.issuer_name AS provider_name,
  co.card_network,
  pm.min_purchase_amount,
  pm.max_purchase_amount,
  co.promotional_apr_percent,
  co.promotional_period_months,
  co.purchase_apr_min_percent AS apr_min_percent,
  co.purchase_apr_max_percent AS apr_max_percent,
  IF(co.promotional_period_months IS NULL, ARRAY<INT64>[], [co.promotional_period_months]) AS term_months,
  co.annual_fee,
  co.late_fee_up_to,
  co.returned_payment_fee_up_to,
  CAST(NULL AS STRING) AS fees_summary,
  co.rewards_rate_description,
  co.signup_bonus_description,
  co.eligibility_summary,
  co.application_disclosure,
  CAST(NULL AS STRING) AS repayment_summary,
  co.responsible_use_note,
  co.terms_url,
  co.effective_start_date,
  co.effective_end_date,
  co.is_active
FROM `affable-seat-501018-q0.golf_products.dim_card_offers` AS co
JOIN `affable-seat-501018-q0.golf_products.dim_payment_methods` AS pm
  ON co.payment_method_id = pm.payment_method_id
WHERE co.is_active
  AND pm.is_active
  AND DATE '2026-07-08' BETWEEN co.effective_start_date AND COALESCE(co.effective_end_date, DATE '9999-12-31')
UNION ALL
SELECT
  'INSTALLMENT' AS option_type,
  io.installment_offer_id AS option_id,
  pm.payment_method_id,
  pm.method_name,
  io.plan_name AS offer_name,
  io.provider_name,
  CAST(NULL AS STRING) AS card_network,
  io.min_purchase_amount,
  io.max_purchase_amount,
  CAST(NULL AS NUMERIC) AS promotional_apr_percent,
  CAST(NULL AS INT64) AS promotional_period_months,
  io.apr_min_percent,
  io.apr_max_percent,
  io.term_months,
  CAST(NULL AS NUMERIC) AS annual_fee,
  CAST(NULL AS NUMERIC) AS late_fee_up_to,
  CAST(NULL AS NUMERIC) AS returned_payment_fee_up_to,
  io.fees_summary,
  CAST(NULL AS STRING) AS rewards_rate_description,
  CAST(NULL AS STRING) AS signup_bonus_description,
  io.eligibility_summary,
  io.disclosure AS application_disclosure,
  io.repayment_summary,
  io.responsible_use_note,
  CAST(NULL AS STRING) AS terms_url,
  io.effective_start_date,
  io.effective_end_date,
  io.is_active
FROM `affable-seat-501018-q0.golf_products.dim_installment_plan_offers` AS io
JOIN `affable-seat-501018-q0.golf_products.dim_payment_methods` AS pm
  ON io.payment_method_id = pm.payment_method_id
WHERE io.is_active
  AND pm.is_active
  AND DATE '2026-07-08' BETWEEN io.effective_start_date AND COALESCE(io.effective_end_date, DATE '9999-12-31');

CREATE OR REPLACE VIEW `affable-seat-501018-q0.golf_products.vw_loyalty_benefits` AS
SELECT
