CREATE OR REPLACE VIEW `affable-seat-501018-q0.golf_products.vw_active_promotions` AS
SELECT
  pr.promotion_id,
  pr.promotion_name,
  pr.promotion_type,
  pr.applies_to_category_id,
  c.category_name,
  c.parent_category,
  pr.applies_to_product_id,
  p.product_name,
  pr.discount_percent,
  pr.discount_amount,
  pr.start_date,
  pr.end_date,
  pr.coupon_code,
  pr.stackable_with_loyalty,
  pr.stackable_with_financing,
