  ON pr.applies_to_product_id = p.product_id
WHERE pr.is_active
  AND DATE '2026-07-08' BETWEEN pr.start_date AND COALESCE(pr.end_date, DATE '9999-12-31');

CREATE OR REPLACE VIEW `affable-seat-501018-q0.golf_products.vw_purchase_support_policies` AS
SELECT
  'SHIPPING' AS policy_type,
  shipping_service_id AS policy_id,
  CAST(NULL AS STRING) AS category_id,
  CAST(NULL AS STRING) AS category_name,
  service_name AS policy_name,
  service_level,
  base_fee,
  free_shipping_threshold,
  estimated_min_business_days,
  estimated_max_business_days,
  oversized_fee,
  supports_pobox,
  supports_ak_hi,
  CAST(NULL AS INT64) AS return_window_days,
  CAST(NULL AS STRING) AS condition_requirements,
  CAST(NULL AS NUMERIC) AS restocking_fee_percent,
  CAST(NULL AS STRING) AS return_shipping_responsibility,
  CAST(NULL AS STRING) AS refund_method,
  CAST(NULL AS INT64) AS coverage_months,
  CAST(NULL AS STRING) AS coverage_provider,
  CAST(NULL AS STRING) AS covered_issues,
  CAST(NULL AS STRING) AS excluded_issues,
  CAST(NULL AS STRING) AS claim_requirements,
  policy_notes
FROM `affable-seat-501018-q0.golf_products.dim_shipping_services`
WHERE is_active
UNION ALL
SELECT
  'RETURN' AS policy_type,
  rp.return_policy_id AS policy_id,
  rp.category_id,
  c.category_name,
  rp.policy_name,
  CAST(NULL AS STRING) AS service_level,
  CAST(NULL AS NUMERIC) AS base_fee,
