  CAST(NULL AS BOOL) AS supports_ak_hi,
  rp.return_window_days,
  rp.condition_requirements,
  rp.restocking_fee_percent,
  rp.return_shipping_responsibility,
  rp.refund_method,
  CAST(NULL AS INT64) AS coverage_months,
  CAST(NULL AS STRING) AS coverage_provider,
  CAST(NULL AS STRING) AS covered_issues,
