LEFT JOIN `affable-seat-501018-q0.golf_products.dim_categories` AS c
  ON rp.category_id = c.category_id
UNION ALL
SELECT
  'WARRANTY' AS policy_type,
  wp.warranty_policy_id AS policy_id,
  wp.category_id,
  c.category_name,
  wp.policy_name,
  CAST(NULL AS STRING) AS service_level,
  CAST(NULL AS NUMERIC) AS base_fee,
  CAST(NULL AS NUMERIC) AS free_shipping_threshold,
  CAST(NULL AS INT64) AS estimated_min_business_days,
  CAST(NULL AS INT64) AS estimated_max_business_days,
  CAST(NULL AS NUMERIC) AS oversized_fee,
  CAST(NULL AS BOOL) AS supports_pobox,
  CAST(NULL AS BOOL) AS supports_ak_hi,
  CAST(NULL AS INT64) AS return_window_days,
  CAST(NULL AS STRING) AS condition_requirements,
  CAST(NULL AS NUMERIC) AS restocking_fee_percent,
  CAST(NULL AS STRING) AS return_shipping_responsibility,
  CAST(NULL AS STRING) AS refund_method,
  wp.coverage_months,
  wp.coverage_provider,
  wp.covered_issues,
  wp.excluded_issues,
  wp.claim_requirements,
  wp.policy_notes
FROM `affable-seat-501018-q0.golf_products.dim_warranty_policies` AS wp
LEFT JOIN `affable-seat-501018-q0.golf_products.dim_categories` AS c
  ON wp.category_id = c.category_id;

